module signal_converter(
    input [3:0] input_signal,
    output reg [2:0] out_signal
);

always @(*) begin
    if (input_signal < 4) begin
        out_signal = input_signal;
    end else if (input_signal < 8) begin
        out_signal = input_signal - 1;
    end else begin
        out_signal = input_signal - 2;
    end
end

endmodule
